import pytest
import requests

BASE_URL = "http://hr-app/api"

def test_create_performance_review_forbidden_role_returns_403(employee_token, employee_id):
    payload = {
        "employee_id": employee_id,
        "period": "2024-Q1",
        "rating": 3,
        "review_text": "Sample review."
    }
    headers = {"Authorization": f"Bearer {employee_token}"}
    resp = requests.post(f"{BASE_URL}/performance-reviews", json=payload, headers=headers)
    assert resp.status_code == 403, f"Expected 403, got {resp.status_code}"
